simple_types.code:
type Transport_State is
  (Initial, Kex_Init_Sent, Kex_Init_Received, Kex_DH, Newkeys_Sent, Authenticated,
   Disconnected);

record_types.code:
type Cipher_Ops is record
   Init        : Cipher_Init;
   Encrypt     : AEAD_Encrypt;
   Decrypt     : AEAD_Decrypt;
   Block_Size  : Positive;
   Key_Len     : Positive;
   IV_Len      : Natural;
   Tag_Len     : Natural;
   Decrypt_Len : Decrypt_Length_Func := null;
end record;

access_types.code:
type AEAD_Decrypt is
  access procedure
    (State : in out Cipher_State; Seq_Num : Uint32; Packet : in out Byte_Array;
     Last  : in out Natural; OK : out Boolean);

type AEAD_Encrypt is
  access procedure
    (State : in out Cipher_State; Seq_Num : Uint32; Packet : in out Byte_Array;
     Last  : in out Natural; OK : out Boolean);

type Cipher_Init is
  access procedure
    (State : out Cipher_State; Key : Byte_Array; IV : Byte_Array; OK : out Boolean);

type Decrypt_Length_Func is
  access function
    (State : Cipher_State; Seq_Num : Uint32; Encrypted : Byte_Array) return Uint32;

type MAC_Compute is
  access function
    (Key : Byte_Array; Sequence_Number : Uint32; Data : Byte_Array) return Byte_Array;

